  'en-US', 'ar', 'fil', 'bn', 'fi', 'nl', 'gl', 'en',
  'ka', 'fr', 'el', 'de', 'gu', 'hi', 'ht', 'id', 'he', 'it', 'hu', 'ja', 'is',
];
